#!/usr/bin/env Rscript
args<-commandArgs(trailingOnly=TRUE);get<-function(k){i<-match(k,args);if(is.na(i))stop('Missing ',k);args[i+1]};out<-get('--outdir');dir.create(out,recursive=TRUE,showWarnings=FALSE);qc<-read.delim(get('--qc'),check.names=FALSE);ex<-read.delim(get('--exclusions'),check.names=FALSE);fl<-read.delim(get('--filtering'),check.names=FALSE);write.table(qc,file.path(out,'multiqc_opensesame_general_stats.tsv'),sep='\t',row.names=FALSE,quote=FALSE);writeLines(c('<html><body><h1>openSesame cohort report</h1>','<h2>Sample QC</h2><pre>',paste(capture.output(print(qc)),collapse='\n'),'</pre><h2>Probe filtering</h2><pre>',paste(capture.output(print(fl)),collapse='\n'),'</pre><p>See pipeline_info for provenance and docs/feature_parity.md for validated feature limits.</p></body></html>'),file.path(out,'cohort_report.html'))
